var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"CSE 레벨이 3을 넘어가고 있잖아?","JPN":"CSEレベルが3を超えている？","ENG":"The CSE level is pushing past 3, right?","TWN":"CSE等級已經突破3了吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"침식파 밀도가 아까보다 빨리 상승하고 있군요.","JPN":"侵食波密度の上昇速度が段々加速しています。","ENG":"The density of Corruption rays is rising faster than before.","TWN":"蝕波密度比剛才上升得更快了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이 추세라면 레벨 4까지 올라가는 것도 금방일 겁니다.","JPN":"この勢いだと、すぐレベル4に達するでしょう。","ENG":"At this rate, it will reach Level 4 soon.","TWN":" 以這個趨勢，應該很快就會升到4 級。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"파티마, 4종 침식체에 대한 대비는 충분한 거야?","JPN":"ファティマ、第4種侵食体への備えは十分なの？","ENG":"Fatima, are we ready for Category 4 C.O.s?","TWN":"法蒂瑪，我們對4級侵蝕體的準備充足嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"가, 갑자기 땅속에서 그런 놈들이 튀어나오지는 않겠지?","JPN":"きゅ、急に地面から湧き出たりしないよね？","ENG":"Th-they won't just burst out of the ground all of a sudden, right?","TWN":"那、那種傢伙不會突然從地底下鑽出來吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"일반적인 4종 침식체들은 차원 돌파 압력을 줄이기 위해 고치 형태로 부상하죠.","JPN":"一般的な第4種侵食体は、次元突破時の圧力を軽減するために、繭の形で浮上します。","ENG":"Ordinary Category 4 C.O.s surface in cocoon form to reduce dimensional breakthrough pressure.","TWN":"一般的4級侵蝕體為了減少次元突破壓力，會以繭的形態浮上來。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"만약 그런 일이 발생한다면, 이터니움을 촉매로 나타날 겁니다.","JPN":"もしそのようなことが発生するなら、エタニウムを触媒にして現れるはずです。","ENG":"If that occurs, they will manifest using Eternium as a catalyst.","TWN":"如果真的發生那種情況，永恆之金就會變為催化劑。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이터니움 보관소가 아직 우리 수중에 있으니 그곳 위주로 감시를 강화하시죠.","JPN":"エタニウム保管所はまだ私たちの手にありますから、そこを中心に監視を強化しましょう。","ENG":"The Eternium depot is still under our control, so let us tighten surveillance there.","TWN":"永恆之金保存所還在我們手中，應該以那裡為主加強監視。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하아… 그렇게 해줘.","JPN":"はあ……そうして。","ENG":"*Sigh...* Please do.","TWN":"唉……就這麼辦吧。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아무런 준비도 없이 4종이랑 마주치는 건 사양이라고.","JPN":"何の準備もできてないまま第4種に遭遇したくないしね。","ENG":"I would rather not meet a Category 4 unprepared.","TWN":"我可不想毫無準備正面遇上4級。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"경호국장님, ARC-EA2 쪽 항구 수비대입니다!","JPN":"警護局長、こちらはARC-EA2の港守備隊です！","ENG":"Miss Fatima, this is the ARC-EA2 harbor guard!","TWN":"警護局長！這裡是ARC-EA2港口守備隊！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"CSE 레벨이 급상승하여 대피에 난항을 겪고 있습니다!","JPN":"CSEレベルが急上昇し、避難が難航しています！","ENG":"CSE levels are spiking. Evacuation is running into heavy trouble!","TWN":"CSE等級急遽上升，撤離工作遇到巨大阻礙！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"또한… 보관소에도… 침식…  몰려… 이런… 쏴!","JPN":"また……保管所にも……侵食……押し寄……くっ……撃て！","ENG":"Also– the depot– infest– C.O.s swar– What the?! Fire!","TWN":"另外……侵蝕也……逼近……保管所……居然……射擊！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"쳇, 어느새 침식체들이 그쪽까지……!","JPN":"ちっ、いつのまに侵食体がそっちまで……！","ENG":"Tch, C.O.s already pushed that far...!","TWN":"嘖，侵蝕體什麼時候到那裡了……！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당장 제가 가도록 하겠습니다!","JPN":"今すぐ向かいます！","ENG":"I will head there at once!","TWN":"我立刻過去！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"안돼.","JPN":"ダメ。","ENG":"No.","TWN":"不行。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"네, 네가 저쪽으로 가고 나면 나는 어떻게 해?","JPN":"あ、あなたがそっちに行ったら、私はどうするの？","ENG":"If you go there, what happens to me?","TWN":"你、你去那邊後我該怎麼辦？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"난 4종까지 갈 것 없이 2종만 나타나도 죽을 거라고!","JPN":"私は第4種どころか、第2種が現れるだけで終わりよ！","ENG":"I would die even to a Category 2, let alone a Category 4!","TWN":"我不用等4級，光是2級出現我就完蛋了啊！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"선로전환기는 실전 투입 전까지 살펴봐야 할 것들이 많아.","JPN":"線路転換器は実戦投入前にチェックしないといけないとこがたくさんある。","ENG":"There is a lot to check on the Track Switcher before live deployment.","TWN":"線路轉換器在正式投入實戰前還有很多要檢查的事項。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"선로전환기는 차원 도약체가 지정된 좌표로 부상하는 경로를 뒤틀어 버리는 장치.","JPN":"あれは次元跳躍体が指定座標に浮上する経路を捻じ曲げる装置。","ENG":"The Track Switcher twists the route of a dimension jumping object ascending to designated coordinates.","TWN":"線路轉換器是個能扭曲次元跳躍體，轉換為指定座標上路徑的裝置。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"마왕에게도 유효할 만큼의 출력을 더해줄 추가적인 시스템을 설계해야 해.","JPN":"魔王にも効くほどの出力を出すためには、追加でシステムを設計しないと。","ENG":"I need to design an additional system that boosts output enough to affect a Demon Lord.","TWN":"必須設計額外的系統，才能讓它能輸出連對魔王都有效。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그렇다면 서둘러야겠군요.","JPN":"ならば急がなければなりませんね。","ENG":"Then we must hurry.","TWN":"那就得趕緊行動了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"지금 로터스 관리국에 그런 걸 할 수 있는 사람은 시니어님뿐이니까요.","JPN":"今のロータス管理局でそんなことができるのは、シニア様だけですから。","ENG":"You are the only one who can do this in Lotus, Senior.","TWN":"現在能做到這件事的人，只有Senior了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"때마침 제5 격납고가 직할 도시의 외곽에 있습니다.","JPN":"ちょうど第5格納庫が直轄都市の外郭にあります。","ENG":"As it happens, Hangar 5 is on the outskirts of the Direct Control City.","TWN":"正好第5機庫位在直轄城市的外圍。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그곳에서 작업을 진행하시죠.","JPN":"そこで作業を進めましょう。","ENG":"Let us proceed with the work there.","TWN":"我們就在那裡進行作業吧。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 그렇게 하자.","JPN":"うん、そうしよう。","ENG":"Okay. Let's do that.","TWN":"好，就那麼做吧。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하… 이럴 땐 내 몸이 두 개 정도 더 있었으면 좋을 텐데.","JPN":"はあ……こんな時は、体が2つあればいいのにって思うよ。","ENG":"Ugh... Times like this, I wish I had two bodies.","TWN":"哈……這種時候就希望我有兩個身體。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그럼 제가 돌봐야 할 문제아가 두 배가 되는 거군요.","JPN":"そうなると、私が世話を焼く問題児が2倍になりますね。","ENG":"That would double the number of problem children I need to watch.","TWN":"那我得善後的問題就變成兩倍了呢。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"씨이… 그래도 나만 한 천재가 둘이면 이 세상도 지금보다 더 많이 바뀌었을걸?","JPN":"くっ……でも、私みたいな天才が2人いれば、この世界は今よりももっと変わってたはずだよ？","ENG":"Grr... Though if there were two geniuses like me, the world would be much further along.","TWN":"嘖……要是有兩個不過像我這樣的天才，這世界的變化應該會比現在更多吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님이 그 천재성으로 공학에 관심을 쏟게 돼서 다행입니다.","JPN":"シニア様がその天才性を工学に活かしてくださってよかったです。","ENG":"I am just glad your genius found its way into engineering.","TWN":"幸好Senior您把那份天賦投注到工程學。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그것조차 없었다면 시니어님은 한 번에 일곱 가지 게임을 하는 히키코모리로 전락했을지도 모르죠.","JPN":"そうでなければ、シニア様は7つのゲームを同時進行する引きこもりになっていたかもしれません。","ENG":"Without even that, you might have become a shut-in who plays seven games at once.","TWN":"要是連那都沒有，您可能會變成同時玩七款遊戲的宅男吧。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그건… 지금도 가끔 해.","JPN":"それは……今もたまにやってるけど。","ENG":"I... still do sometimes.","TWN":"那個……我現在偶爾也會這樣……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내가 얘기했었나?","JPN":"話したことあったっけ？","ENG":"Did I ever tell you?","TWN":"我有說過嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내가 꼬맹이였을 적에 타이탄 덕분에 살아남을 수 있었던 거.","JPN":"子どもの頃、タイタンのおかげで生き残れたって。","ENG":"When I was little, I survived thanks to Titan.","TWN":"我小時候能活下來，都是拜泰坦所賜。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"조금이라도 술에 취하시면 언제나 꺼내는 주제였습니다. 잊을 리가 없죠.","JPN":"少しでも酒が入ると出す話題ですね。忘れるわけがありません。","ENG":"The slightest bit of alcohol and you always bring that up. I could not forget if I tried.","TWN":"您只要喝醉就會講這個故事。我怎麼可能忘記。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};